import { Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router } from '@angular/router';
import { Match } from '../../core/models';
import { AvatarComponent } from '../../shared/avatar/avatar.component';

@Component({
  selector: 'app-matches',
  standalone: true,
  imports: [CommonModule, AvatarComponent],
  templateUrl: './matches.component.html',
  styleUrl: './matches.component.css',
})
export class MatchesComponent {
  private router = inject(Router);

  // Backend-provided data — typed signal per the data contract.
  readonly matches = signal<Match[]>([
    { id: 'm1', userId: 'u201', name: 'Priya Nair', jobTitle: 'Senior Data Scientist', employer: 'Helix Bio', lastMessage: 'Ramen debate settled — I know the spot. Free Thursday?', lastActivity: '2m', unread: 2, online: true },
    { id: 'm2', userId: 'u203', name: 'Sofia Ramos', jobTitle: 'Brand Strategist', employer: 'Wieden+Kennedy', lastMessage: 'That gallery opening looks amazing, count me in!', lastActivity: '1h', unread: 0, online: true },
    { id: 'm3', userId: 'u205', name: 'Aisha Khan', jobTitle: 'Product Manager', employer: 'Notion', lastMessage: 'Haiku accepted. Your move. 😌', lastActivity: '3h', unread: 1, online: false },
    { id: 'm4', userId: 'u208', name: 'Jordan Lee', jobTitle: 'UX Researcher', employer: 'Airbnb', lastMessage: 'You matched — say hi 👋', lastActivity: '1d', unread: 0, online: false },
    { id: 'm5', userId: 'u211', name: 'Elena Petrova', jobTitle: 'VC Associate', employer: 'Index Ventures', lastMessage: 'Loved your take on calm software.', lastActivity: '2d', unread: 0, online: false },
  ]);

  readonly newMatches = computed(() => this.matches().filter((m) => m.lastMessage.includes('matched')));
  readonly conversations = computed(() => this.matches().filter((m) => !m.lastMessage.includes('matched')));

  open(match: Match): void {
    this.router.navigate(['/matches', match.id]);
  }

  goDiscover(): void {
    this.router.navigate(['/feed']);
  }
}
